  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate, useLocation } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData, getViewportConstellations } from '../../../API/Api';
  6→import supabase from '../../utils/supabaseClient';
  7→import useUniverseCamera from './hooks/useUniverseCamera';
  8→import useCosmicGravity from './hooks/useCosmicGravity';
  9→import useConstellationLinkMode from './hooks/useConstellationLinkMode';
 10→
 11→import DeepSpaceLayer from './layers/DeepSpaceLayer';
 12→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 13→import NebulaLayer from './layers/NebulaLayer';
 14→import InteractiveLayer from './layers/InteractiveLayer';
 15→import WormholeLayer from './layers/WormholeLayer';
 16→import ConstellationLayer from './layers/ConstellationLayer';
 17→import UniverseMinimap from './components/UniverseMinimap';
 18→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
 19→import {
 20→    buildSectorIndex,
 21→    computeGalaxyCentroids,
 22→    computeConstellationPullOffsets,
 23→    computeSectorKey,
 24→    getNeighborSectorKeys,
 25→} from './utils/cosmicPhysics';
 26→import { computeConstellationChains, assignChainColors } from './utils/constellationUtils';
 27→import { handleClickProfile } from '../../../helpers/handleClicks';
 28→import styles from './Universe.module.css';
 29→
 30→const SECTOR_SIZE = 2000;
 31→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 32→
 33→const Universe = () => {
 34→    const navigate = useNavigate();
 35→    const location = useLocation();
 36→    const { user, session } = useAuth();
 37→    const userId = user?.userData?.[0]?.id || null;
 38→
 39→    const fetchDebounceRef = useRef(null);
 40→    const settleDebounceRef = useRef(null);
 41→    const lastSettledPayloadRef = useRef('');
 42→    const initialFetchResolvedRef = useRef(false);
 43→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 44→    const ownGalaxyLookupStartedRef = useRef(false);
 45→    const constellationFlyToRef = useRef(location.state?.flyToConstellation || null);
 46→
 47→    const [posts, setPosts] = useState(new Map());
 48→    const [selectedPost, setSelectedPost] = useState(null);
 49→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 50→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 51→    const [pulsingId, setPulsingId] = useState(null);
 52→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 53→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 54→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 55→    const [wormholes, setWormholes] = useState([]);
 56→    const [isWarping, setIsWarping] = useState(false);
 57→    const [constellations, setConstellations] = useState([]);
 58→    const [linkModeError, setLinkModeError] = useState(null);
 59→    const [focusedConstellation, setFocusedConstellation] = useState(null);
 60→
 61→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 62→    const [centroids, setCentroids] = useState([]);
 63→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 64→    const [similarPairs, setSimilarPairs] = useState([]);
 65→    const [starPulls, setStarPulls] = useState([]);
 66→
 67→    // Shared ref: prevents camera pan while dragging a star
 68→    const isStarDragging = useRef(false);
 69→
 70→    const {
 71→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 72→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 73→    } = useUniverseCamera(userId, hasOwnPosts, isStarDragging);
 74→
 75→    const {
 76→        isLinkMode, firstStar, secondStar, isSubmitting, linkModeStatus,
 77→        toggleLinkMode, cancelLinkMode, handleStarClickInLinkMode, submitLink,
 78→    } = useConstellationLinkMode(userId, session);
 79→
 80→    const [labelInput, setLabelInput] = useState('');
 81→
 82→    const focusedStarIds = useMemo(() => {
 83→        if (!focusedConstellation) return null;
 84→        return new Set([focusedConstellation.star_id_a, focusedConstellation.star_id_b]);
 85→    }, [focusedConstellation]);
 86→
 87→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 88→    const showTitles = zoom > 0.5;
 89→
 90→    // Sector partitioning for scalable local gravity math.
 91→    const postSectorIndex = useMemo(() => (
 92→        buildSectorIndex(
 93→            postArray,
 94→            (post) => ({
 95→                x: post?.display_x ?? post?.universe_x,
 96→                y: post?.display_y ?? post?.universe_y,
 97→            }),
 98→            SECTOR_SIZE
 99→        )
100→    ), [postArray]);
101→
102→    const centerSectorKey = useMemo(
103→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
104→        [centerWorld.x, centerWorld.y]
105→    );
106→
107→    const activeSectorKeys = useMemo(
108→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
109→        [centerSectorKey]
110→    );
111→
112→    const activePosts = useMemo(() => {
113→        if (activeSectorKeys.size === 0) return postArray;
114→
115→        const next = [];
116→        for (const key of activeSectorKeys) {
117→            const bucket = postSectorIndex.get(key);
118→            if (bucket?.length) next.push(...bucket);
119→        }
120→        return next;
121→    }, [postArray, postSectorIndex, activeSectorKeys]);
122→
123→    const activePostIds = useMemo(() => {
124→        const ids = new Set();
125→        for (const post of activePosts) {
126→            if (post?.id) ids.add(post.id);
127→        }
128→        return ids;
129→    }, [activePosts]);
130→
131→    const { centroidByUser } = useMemo(
132→        () => computeGalaxyCentroids(postArray),
133→        [postArray]
134→    );
135→
136→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
137→    const hashGalaxies = useMemo(() => {
138→        const seen = new Map();
139→        for (const post of postArray) {
140→            const uid = post.users?.id ?? post.user_id;
141→            if (!uid || seen.has(uid)) continue;
142→            const hash = userHomeCoords(uid);
143→            seen.set(uid, {
144→                userId: uid,
145→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
146→                x: hash.x,
147→                y: hash.y,
148→            });
149→        }
150→        return Array.from(seen.values());
151→    }, [postArray]);
152→
153→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
154→    const centroidTargets = useMemo(() => {
155→        const map = new Map();
156→        for (const c of centroids) {
157→            if (c.galaxy_x != null && c.galaxy_y != null) {
158→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
159→            }
160→        }
161→        return map;
162→    }, [centroids]);
163→
164→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
165→    const {
166→        galaxyPositions,
167→        starPullOffsets,
168→        isSettled,
169→        galaxyEdges: effectiveGalaxyEdges,
170→        hasEmbeddingGravity,
171→    } = useCosmicGravity({
172→        galaxies: hashGalaxies,
173→        centroidTargets,
174→        edges: galaxyEdges,
175→        posts: postArray,
176→        starPulls,
177→        centroidByUser,
178→        activeSectorKeys,
179→        activePostIds,
180→        sectorSize: SECTOR_SIZE,
181→    });
182→
183→    // ── Render galaxies = hash galaxies with animated positions ──────
184→    const galaxies = useMemo(() => {
185→        return hashGalaxies.map(g => {
186→            const animated = galaxyPositions.get(g.userId);
187→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
188→        });
189→    }, [hashGalaxies, galaxyPositions]);
190→
191→    // Home position for distance tracker — same resolution as auto-focus.
192→    const homePosition = useMemo(() => {
193→        if (!userId) return { x: 0, y: 0 };
194→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
195→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
196→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
197→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
198→
199→    const getComputedStarPosition = useCallback((post) => {
200→        if (!post) return null;
201→
202→        const uid = post.users?.id ?? post.user_id;
203→        const hashGal = userHomeCoords(uid);
204→        const animGal = galaxyPositions.get(uid);
205→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
206→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
207→        const pull = starPullOffsets.get(post.id);
208→
209→        const baseX = post.universe_x ?? post.display_x;
210→        const baseY = post.universe_y ?? post.display_y;
211→        if (baseX == null || baseY == null) return null;
212→
213→        return {
214→            x: baseX + galDx + (pull?.dx ?? 0),
215→            y: baseY + galDy + (pull?.dy ?? 0),
216→        };
217→    }, [galaxyPositions, starPullOffsets]);
218→
219→    // ── Hoisted computedStarPositions for sharing across layers ──────
220→    const computedStarPositions = useMemo(() => {
221→        const map = new Map();
222→        for (const post of postArray) {
223→            const uid = post.users?.id ?? post.user_id;
224→            const hashGal = userHomeCoords(uid);
225→            const animGal = galaxyPositions.get(uid);
226→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
227→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
228→            const pull = starPullOffsets.get(post.id);
229→
230→            const baseX = post.universe_x ?? post.display_x;
231→            const baseY = post.universe_y ?? post.display_y;
232→            if (baseX == null || baseY == null) continue;
233→
234→            let x = baseX + galDx + (pull?.dx ?? 0);
235→            let y = baseY + galDy + (pull?.dy ?? 0);
236→
237→            map.set(post.id, { x, y });
238→        }
239→        return map;
240→    }, [postArray, galaxyPositions, starPullOffsets]);
241→
242→    // ── Constellation pull offsets (spring constraint) ─────────────
243→    const acceptedConstellations = useMemo(
244→        () => constellations.filter(c => c.status === 'accepted'),
245→        [constellations]
246→    );
247→
248→    const constellationPullOffsets = useMemo(
249→        () => computeConstellationPullOffsets(acceptedConstellations, computedStarPositions),
250→        [acceptedConstellations, computedStarPositions]
251→    );
252→
253→    // ── Final star positions with constellation pull applied ───────
254→    const finalStarPositions = useMemo(() => {
255→        if (constellationPullOffsets.size === 0) return computedStarPositions;
256→
257→        const map = new Map(computedStarPositions);
258→        for (const [postId, offset] of constellationPullOffsets) {
259→            const pos = map.get(postId);
260→            if (pos) {
261→                map.set(postId, {
262→                    x: pos.x + offset.dx,
263→                    y: pos.y + offset.dy,
264→                });
265→            }
266→        }
267→        return map;
268→    }, [computedStarPositions, constellationPullOffsets]);
269→
270→    // ── Constellation chain colors ────────────────────────────────
271→    const chainColors = useMemo(() => {
272→        const chains = computeConstellationChains(acceptedConstellations);
273→        return assignChainColors(chains);
274→    }, [acceptedConstellations]);
275→
276→    // ── Map star ID → constellation chain color for ring indicators ─
277→    const constellationStarColors = useMemo(() => {
278→        const map = new Map();
279→        for (const c of acceptedConstellations) {
280→            const color = chainColors.get(c.id);
281→            if (!color) continue;
282→            if (!map.has(c.star_id_a)) map.set(c.star_id_a, color);
283→            if (!map.has(c.star_id_b)) map.set(c.star_id_b, color);
284→        }
285→        return map;
286→    }, [acceptedConstellations, chainColors]);
287→
288→    // Resolve logged-in user's galaxy target independently from viewport data.
289→    useEffect(() => {
290→        if (!userId) return;
291→        if (ownGalaxyLookupStartedRef.current) return;
292→
293→        ownGalaxyLookupStartedRef.current = true;
294→        let cancelled = false;
295→
296→        const resolveOwnGalaxyTarget = async () => {
297→            try {
298→                const { data, error } = await supabase
299→                    .from('galaxy_centroids')
300→                    .select('galaxy_x, galaxy_y')
301→                    .eq('user_id', userId)
302→                    .maybeSingle();
303→
304→                if (cancelled) return;
305→
306→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
307→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
308→                    setHasOwnPosts(true);
309→                    return;
310→                }
311→            } catch (err) {
312→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
313→            }
314→
315→            if (!cancelled) {
316→                setOwnGalaxyTarget(userHomeCoords(userId));
317→            }
318→        };
319→
320→        resolveOwnGalaxyTarget();
321→
322→        return () => {
323→            cancelled = true;
324→        };
325→    }, [userId]);
326→
327→    // One-time wormhole fetch on mount
328→    useEffect(() => {
329→        let cancelled = false;
330→
331→        const fetchWormholes = async () => {
332→            try {
333→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
334→                    similarity_threshold: 0.7,
335→                    min_distance: 0,
336→                    max_pairs: 30,
337→                });
338→                if (cancelled) return;
339→                if (error) {
340→                    console.warn('[universe] wormhole fetch error:', error.message);
341→                    return;
342→                }
343→                console.log('[universe] wormhole pairs:', data);
344→                if (Array.isArray(data) && data.length > 0) {
345→                    setWormholes(data);
346→                }
347→            } catch (err) {
348→                if (!cancelled) {
349→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
350→                }
351→            }
352→        };
353→
354→        fetchWormholes();
355→        return () => { cancelled = true; };
356→    }, []);
357→
358→    // Debounced fetch on camera/zoom change
359→    useEffect(() => {
360→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
361→
362→        fetchDebounceRef.current = setTimeout(async () => {
363→            const bounds = getViewportBounds();
364→            try {
365→                const result = await getUniversePosts(
366→                    bounds.minX,
367→                    bounds.maxX,
368→                    bounds.minY,
369→                    bounds.maxY,
370→                    200
371→                );
372→                if (result?.data) {
373→                    setPosts(prev => {
374→                        const next = new Map(prev);
375→                        for (const post of result.data) {
376→                            next.set(post.id, post);
377→                        }
378→                        return next;
379→                    });
380→                    if (userId && hasOwnPosts !== true) {
381→                        const ownsAny = result.data.some(p =>
382→                            (p.users?.id ?? p.user_id) === userId
383→                        );
384→                        if (ownsAny) setHasOwnPosts(true);
385→                    }
386→                }
387→                // Keep server gravity data as fallback when embeddings are absent in payload.
388→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
389→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
390→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
391→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
392→
393→                // Fetch constellations for visible posts
394→                if (result?.data?.length > 0) {
395→                    const visibleIds = result.data.map(p => p.id);
396→                    try {
397→                        const constResult = await getViewportConstellations(visibleIds);
398→                        if (constResult?.data) {
399→                            setConstellations(constResult.data);
400→                        }
401→                    } catch (constErr) {
402→                        console.warn('[universe] constellation fetch failed:', constErr?.message || constErr);
403→                    }
404→                }
405→            } catch (err) {
406→                console.error('Failed to fetch universe posts:', err);
407→            } finally {
408→                if (!initialFetchResolvedRef.current) {
409→                    initialFetchResolvedRef.current = true;
410→                    setIsInitialLoading(false);
411→                }
412→            }
413→        }, 400);
414→
415→        return () => {
416→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
417→        };
418→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
419→
420→    const handleStarClick = useCallback(async (post) => {
421→        if (isFlying.current) return;
422→
423→        // Intercept for link mode
424→        if (isLinkMode) {
425→            setLinkModeError(null);
426→            const result = await handleStarClickInLinkMode(post);
427→            if (result?.error) {
428→                setLinkModeError(result.error);
429→                setTimeout(() => setLinkModeError(null), 3000);
430→            }
431→            return;
432→        }
433→
434→        setSelectedPost(post);
435→        setSelectedGalaxy(null);
436→        setGalaxyProfile(null);
437→
438→        const position = getComputedStarPosition(post);
439→        if (!position) return;
440→
441→        flyTo(position.x, position.y, 1.2, () => {
442→            setPulsingId(post.id);
443→            setTimeout(() => setPulsingId(null), 700);
444→        });
445→    }, [flyTo, getComputedStarPosition, isFlying, isLinkMode, handleStarClickInLinkMode]);
446→
447→    const handleGalaxyClick = useCallback(async (galaxy) => {
448→        if (isFlying.current) return;
449→        setSelectedGalaxy(galaxy);
450→        setSelectedPost(null);
451→        setGalaxyProfile(null);
452→        flyTo(galaxy.x, galaxy.y, 0.8);
453→
454→        try {
455→            const data = await getUserData(galaxy.userId);
456→            const profile = data?.userData?.[0] || null;
457→            setGalaxyProfile(profile);
458→        } catch (err) {
459→            console.error('Failed to fetch galaxy profile:', err);
460→        }
461→    }, [flyTo, isFlying]);
462→
463→    const handleReadPost = useCallback(() => {
464→        if (!selectedPost) return;
465→        navigate(`/home/post/${selectedPost.id}`);
466→    }, [selectedPost, navigate]);
467→
468→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
469→        if (mode === 'drag') {
470→            jumpTo(worldX, worldY);
471→            return;
472→        }
473→        flyTo(worldX, worldY, zoom);
474→    }, [flyTo, jumpTo, zoom]);
475→
476→    // Enrich wormhole positions with live gravity-computed post coords
477→    const enrichedWormholes = useMemo(() => {
478→        return wormholes.map(wh => {
479→            const postA = posts.get(wh.post_a);
480→            const postB = posts.get(wh.post_b);
481→            const posA = postA ? getComputedStarPosition(postA) : null;
482→            const posB = postB ? getComputedStarPosition(postB) : null;
483→            return {
484→                ...wh,
485→                a_x: posA?.x ?? wh.a_x,
486→                a_y: posA?.y ?? wh.a_y,
487→                b_x: posB?.x ?? wh.b_x,
488→                b_y: posB?.y ?? wh.b_y,
489→            };
490→        });
491→    }, [wormholes, posts, getComputedStarPosition]);
492→
493→    // Find wormhole connection for a given post (if any)
494→    const getWormholeForPost = useCallback((postId) => {
495→        if (!postId || enrichedWormholes.length === 0) return null;
496→        for (const wh of enrichedWormholes) {
497→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
498→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
499→        }
500→        return null;
501→    }, [enrichedWormholes]);
502→
503→    const handleWormholeTravel = useCallback(() => {
504→        if (!selectedPost || isFlying.current) return;
505→        const match = getWormholeForPost(selectedPost.id);
506→        if (!match) return;
507→        const { wormhole, side } = match;
508→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
509→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
510→        setSelectedPost(null);
511→        setIsWarping(true);
512→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
513→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
514→
515→    // Find constellation links for a given post
516→    const getConstellationLinksForPost = useCallback((postId) => {
517→        if (!postId || acceptedConstellations.length === 0) return [];
518→        const links = [];
519→        for (const c of acceptedConstellations) {
520→            if (c.star_id_a === postId) {
521→                links.push({ constellation: c, targetStarId: c.star_id_b, targetTitle: c.b_title || 'Unnamed Star', label: c.label });
522→            } else if (c.star_id_b === postId) {
523→                links.push({ constellation: c, targetStarId: c.star_id_a, targetTitle: c.a_title || 'Unnamed Star', label: c.label });
524→            }
525→        }
526→        return links;
527→    }, [acceptedConstellations]);
528→
529→    const handleConstellationTravel = useCallback((targetStarId, constellation) => {
530→        if (isFlying.current) return;
531→        // Try live computed position first
532→        let targetPos = finalStarPositions.get(targetStarId);
533→        // Fallback to raw RPC positions from the constellation record
534→        if (!targetPos && constellation) {
535→            if (constellation.star_id_a === targetStarId && constellation.a_universe_x != null) {
536→                targetPos = { x: constellation.a_universe_x, y: constellation.a_universe_y };
537→            } else if (constellation.star_id_b === targetStarId && constellation.b_universe_x != null) {
538→                targetPos = { x: constellation.b_universe_x, y: constellation.b_universe_y };
539→            }
540→        }
541→        if (!targetPos) return;
542→        setSelectedPost(null);
543→        flyTo(targetPos.x, targetPos.y, zoom);
544→    }, [finalStarPositions, flyTo, isFlying, zoom]);
545→
546→    const handleConstellationFocus = useCallback((link) => {
547→        if (isLinkMode) return;
548→        setFocusedConstellation(link);
549→        setSelectedPost(null);
550→    }, [isLinkMode]);
551→
552→    const handleDismissFocus = useCallback(() => {
553→        setFocusedConstellation(null);
554→    }, []);
555→
556→    // One-time auto focus after first payload is loaded.
557→    // Skip if we have a constellation flyTo target — that effect handles it instead.
558→    useEffect(() => {
559→        if (!userId) return;
560→        if (isInitialLoading) return;
561→        if (hasAutoFocusedOwnGalaxyRef.current) return;
562→        if (constellationFlyToRef.current) return;
563→
564→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
565→        const target = ownGalaxy
566→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
567→            : (centroidTargets.get(userId) || ownGalaxyTarget);
568→
569→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
570→        if (!target) return;
571→
572→        hasAutoFocusedOwnGalaxyRef.current = true;
573→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
574→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
575→
576→    // Fly to constellation midpoint when arriving from a notification link.
577→    useEffect(() => {
578→        const target = constellationFlyToRef.current;
579→        if (!target) return;
580→        if (isInitialLoading) return;
581→
582→        const posA = finalStarPositions.get(target.starIdA);
583→        const posB = finalStarPositions.get(target.starIdB);
584→        if (!posA || !posB) return;
585→
586→        constellationFlyToRef.current = null;
587→        hasAutoFocusedOwnGalaxyRef.current = true;
588→
589→        const mx = (posA.x + posB.x) / 2;
590→        const my = (posA.y + posB.y) / 2;
591→        flyTo(mx, my, 1.0);
592→
593→        // Clear navigation state so refreshing doesn't re-trigger
594→        navigate(location.pathname, { replace: true, state: {} });
595→    }, [isInitialLoading, finalStarPositions, flyTo, navigate, location.pathname]);
596→
597→    const settledPayload = useMemo(() => {
598→        if (!isSettled || activePosts.length === 0) return [];
599→
600→        const payload = [];
601→        for (const post of activePosts) {
602→            if (!post?.id) continue;
603→            const pos = getComputedStarPosition(post);
604→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
605→
606→            payload.push({
607→                post_id: post.id,
608→                settled_x: Math.round(pos.x * 100) / 100,
609→                settled_y: Math.round(pos.y * 100) / 100,
610→            });
611→        }
612→
613→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
614→        return payload;
615→    }, [activePosts, getComputedStarPosition, isSettled]);
616→
617→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
618→    useEffect(() => {
619→        if (!ENABLE_SETTLED_RPC_SAVE) return;
620→        if (!isSettled || settledPayload.length === 0) return;
621→
622→        const signature = JSON.stringify(settledPayload);
623→        if (signature === lastSettledPayloadRef.current) return;
624→
625→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
626→        settleDebounceRef.current = setTimeout(async () => {
627→            lastSettledPayloadRef.current = signature;
628→            try {
629→                const { error } = await supabase.rpc('save_universe_settled_positions', {
630→                    positions_payload: settledPayload,
631→                });
632→                if (error) {
633→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
634→                }
635→            } catch (err) {
636→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
637→            }
638→        }, 1200);
639→
640→        return () => {
641→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
642→        };
643→    }, [isSettled, settledPayload]);
644→
645→    // ESC key to cancel link mode or dismiss constellation focus
646→    useEffect(() => {
647→        if (!isLinkMode && !focusedConstellation) return;
648→        const handleKeyDown = (e) => {
649→            if (e.key === 'Escape') {
650→                if (isLinkMode) cancelLinkMode();
651→                if (focusedConstellation) setFocusedConstellation(null);
652→            }
653→        };
654→        window.addEventListener('keydown', handleKeyDown);
655→        return () => window.removeEventListener('keydown', handleKeyDown);
656→    }, [isLinkMode, cancelLinkMode, focusedConstellation]);
657→
658→    useEffect(() => {
659→        return () => {
660→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
661→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
662→        };
663→    }, []);
664→
665→    return (
666→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
667→            <button className={styles.backButton} onClick={() => navigate('/home')}>
668→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
669→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
670→                </svg>
671→                Back
672→            </button>
673→
674→            {userId && (
675→                <button
676→                    className={`${styles.linkModeButton} ${isLinkMode ? styles.linkModeActive : ''}`}
677→                    onClick={toggleLinkMode}
678→                    disabled={isSubmitting}
679→                >
680→                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
681→                        <path d="M3.9 12c0-1.71 1.39-3.1 3.1-3.1h4V7H7c-2.76 0-5 2.24-5 5s2.24 5 5 5h4v-1.9H7c-1.71 0-3.1-1.39-3.1-3.1zM8 13h8v-2H8v2zm9-6h-4v1.9h4c1.71 0 3.1 1.39 3.1 3.1s-1.39 3.1-3.1 3.1h-4V17h4c2.76 0 5-2.24 5-5s-2.24-5-5-5z"/>
682→                    </svg>
683→                    {isLinkMode
684→                        ? (secondStar ? 'Naming link...' : (firstStar ? 'Select second star...' : 'Select your star...'))
685→                        : 'Link Stars'}
686→                </button>
687→            )}
688→
689→            {isLinkMode && linkModeStatus === 'enter_label' && (
690→                <div className={styles.labelInputPanel}>
691→                    <div className={styles.labelInputHeader}>
692→                        Link "{firstStar?.title}" ↔ "{secondStar?.title}"
693→                    </div>
694→                    <input
695→                        className={styles.labelInputField}
696→                        type="text"
697→                        placeholder="Name this constellation (optional)"
698→                        value={labelInput}
699→                        onChange={(e) => setLabelInput(e.target.value)}
700→                        onKeyDown={(e) => {
701→                            if (e.key === 'Enter') {
702→                                submitLink(labelInput);
703→                                setLabelInput('');
704→                            }
705→                        }}
706→                        autoFocus
707→                    />
708→                    <div className={styles.labelInputActions}>
709→                        <button
710→                            className={styles.labelInputCreate}
711→                            disabled={isSubmitting}
712→                            onClick={() => {
713→                                submitLink(labelInput);
714→                                setLabelInput('');
715→                            }}
716→                        >
717→                            {isSubmitting ? 'Creating...' : 'Create Link'}
718→                        </button>
719→                        <button
720→                            className={styles.labelInputCancel}
721→                            onClick={() => {
722→                                cancelLinkMode();
723→                                setLabelInput('');
724→                            }}
725→                        >
726→                            Cancel
727→                        </button>
728→                    </div>
729→                </div>
730→            )}
731→
732→            {isLinkMode && linkModeStatus !== 'enter_label' && (
733→                <div className={styles.linkModeIndicator}>
734→                    <span>
735→                        {linkModeError
736→                            ? linkModeError
737→                            : firstStar
738→                                ? `Selected "${firstStar.title}" — now click another user's star`
739→                                : 'Click one of your stars to begin'}
740→                    </span>
741→                    <button className={styles.linkModeCancel} onClick={cancelLinkMode}>Cancel</button>
742→                </div>
743→            )}
744→
745→            <div className={styles.distanceTracker}>
746→                {(() => {
747→                    const dx = centerWorld.x - homePosition.x;
748→                    const dy = centerWorld.y - homePosition.y;
749→                    const dist = Math.round(Math.sqrt(dx * dx + dy * dy));
750→                    return dist < 50
751→                        ? 'Home'
752→                        : `${dist.toLocaleString()} Lightyears from Home`;
753→                })()}
754→            </div>
755→
756→            {isInitialLoading && (
757→                <div className={styles.loadingOverlay}>
758→                    <div className={styles.loadingCard}>
759→                        <div className={styles.loadingSpinner} />
760→                        <div className={styles.loadingText}>Loading universe...</div>
761→                    </div>
762→                </div>
763→            )}
764→
765→            <Stage
766→                ref={stageRef}
767→                width={stageSize.width}
768→                height={stageSize.height}
769→                {...stageEvents}
770→                onClick={(e) => {
771→                    if (focusedConstellation && e.target === e.target.getStage()) {
772→                        handleDismissFocus();
773→                    }
774→                }}
775→                onTap={(e) => {
776→                    if (focusedConstellation && e.target === e.target.getStage()) {
777→                        handleDismissFocus();
778→                    }
779→                }}
780→            >
781→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
782→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
783→                <NebulaLayer
784→                    layerProps={getLayerProps(0.85)}
785→                    galaxies={galaxies}
786→                    centroids={centroids}
787→                />
788→                {enrichedWormholes.length > 0 && (
789→                    <WormholeLayer
790→                        layerProps={getLayerProps(1.0)}
791→                        wormholes={enrichedWormholes}
792→                        zoom={zoom}
793→                    />
794→                )}
795→                {constellations.length > 0 && (
796→                    <ConstellationLayer
797→                        layerProps={getLayerProps(1.0)}
798→                        constellations={constellations}
799→                        computedStarPositions={finalStarPositions}
800→                        zoom={zoom}
801→                        chainColors={chainColors}
802→                        userId={userId}
803→                        onConstellationFocus={handleConstellationFocus}
804→                        focusedConstellationId={focusedConstellation?.id || null}
805→                    />
806→                )}
807→                <InteractiveLayer
808→                    layerProps={getLayerProps(1.0)}
809→                    posts={postArray}
810→                    galaxies={galaxies}
811→                    zoom={zoom}
812→                    showTitles={showTitles}
813→                    pulsingId={pulsingId}
814→                    onStarClick={handleStarClick}
815→                    onGalaxyClick={handleGalaxyClick}
816→                    galaxyPositions={galaxyPositions}
817→                    starPullOffsets={starPullOffsets}
818→                    similarPairs={similarPairs}
819→                    galaxyEdges={effectiveGalaxyEdges}
820→                    activePostIds={activePostIds}
821→                    useEmbeddingBridges={hasEmbeddingGravity}
822→                    camera={camera}
823→                    stageSize={stageSize}
824→                    computedStarPositions={finalStarPositions}
825→                    constellationStarColors={constellationStarColors}
826→                    focusedStarIds={focusedStarIds}
827→                />
