829→
830→            {isWarping && <div className={styles.warpOverlay} />}
831→
832→            <UniverseMinimap
833→                galaxies={galaxies}
834→                camera={camera}
835→                zoom={zoom}
836→                stageSize={stageSize}
837→                onNavigate={handleMinimapNavigate}
838→                constellations={acceptedConstellations}
839→                computedStarPositions={finalStarPositions}
840→                focusedConstellationId={focusedConstellation?.id || null}
841→            />
842→
843→            {selectedGalaxy && galaxyProfile && (
844→                <div className={styles.galaxyPreviewPanel}>
845→                    <button
846→                        className={styles.galaxyPreviewClose}
847→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
848→                    >
849→                        &times;
850→                    </button>
