862→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
863→                        </div>
864→                        {galaxyProfile.bio && (
865→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
866→                        )}
867→                        <button
868→                            className={styles.galaxyPreviewVisitBtn}
869→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
870→                        >
