897→                    <div className={styles.previewLikes}>
898→                        {(() => {
899→                            const count = selectedPost.like_count != null
900→                                ? selectedPost.like_count
901→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
902→                                    ? selectedPost.likes[0].count : 0);
903→                            return `${count} like${count !== 1 ? 's' : ''}`;
904→                        })()}
905→                    </div>
906→                    <div className={styles.previewActions}>
907→                        <button className={styles.previewReadBtn} onClick={handleReadPost}>
908→                            Read
