// ── Constants ──────────────────────────────────────────────────────────
const MAX_SPEED = 12;
const ACCEL = 0.25;
const BRAKE = 0.15;
const FRICTION = 0.985;
const TURN_RATE = 0.035;
const MIN_Z = 0.5;
const MAX_Z = 800;
const SPAWN_Z_RANGE = 400;
const SORT_INTERVAL = 5;
const TARGET_DIST_MAX = 150;
const TARGET_Z_MIN = 2;
const TWO_PI = Math.PI * 2;

/** Parse "#5f92ff" → { r, g, b } */
const parseHex = (hex) => ({
    r: parseInt(hex.slice(1, 3), 16),
    g: parseInt(hex.slice(3, 5), 16),
    b: parseInt(hex.slice(5, 7), 16),
});

/** Seeded pseudo-random from integer seed */
const seededRandom = (seed) => {
    let s = seed | 0;
    return () => {
        s = (s * 1664525 + 1013904223) | 0;
        return ((s >>> 0) / 4294967296);
    };
};

const useRocketMode = () => {
    const isActiveRef = useRef(false);
    const rocketPosRef = useRef({ x: 0, y: 0 });
    const headingRef = useRef(-Math.PI / 2);
    const velocityRef = useRef(0);
    const starsRef = useRef([]);
    const sortedIndicesRef = useRef([]);
    const keysRef = useRef({ w: false, s: false, a: false, d: false });
    const targetIndexRef = useRef(-1);
    const frameRef = useRef(0);
    const layerRef = useRef(null);
    const rafRef = useRef(null);
    const stageSizeRef = useRef({ width: 0, height: 0 });

    const sortStars = useCallback(() => {
        const stars = starsRef.current;
        const indices = sortedIndicesRef.current;
        // Simple insertion sort — fast for nearly-sorted arrays
        for (let i = 1; i < indices.length; i++) {
            const key = indices[i];
            let j = i - 1;
            while (j >= 0 && stars[indices[j]].z < stars[key].z) {
                indices[j + 1] = indices[j];
                j--;
            }
            indices[j + 1] = key;
        }
    }, []);

    const tick = useCallback(() => {
        if (!isActiveRef.current) return;

        const keys = keysRef.current;
        const pos = rocketPosRef.current;
        const stars = starsRef.current;
        const size = stageSizeRef.current;

        // ── Heading ────────────────────────────────────────────────
        if (keys.a) headingRef.current -= TURN_RATE;
        if (keys.d) headingRef.current += TURN_RATE;

        // ── Velocity ───────────────────────────────────────────────
        if (keys.w) {
            velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
        } else if (keys.s) {
            velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
        } else {
            velocityRef.current *= FRICTION;
            if (velocityRef.current < 0.01) velocityRef.current = 0;
        }

        const heading = headingRef.current;
        const velocity = velocityRef.current;

        // ── Position ───────────────────────────────────────────────
        pos.x += Math.cos(heading) * velocity;
        pos.y += Math.sin(heading) * velocity;

        // ── Z update + recycle ─────────────────────────────────────
        const zStep = velocity * 0.5;
        for (let i = 0; i < stars.length; i++) {
            const star = stars[i];
            star.z -= zStep;
            if (star.z < MIN_Z) {
                star.z = MAX_Z - Math.random() * SPAWN_Z_RANGE;
                star.worldX = pos.x + (Math.random() - 0.5) * 4000;
                star.worldY = pos.y + (Math.random() - 0.5) * 4000;
            }
        }

        // ── Sort (every N frames) ─────────────────────────────────
        frameRef.current++;
        if (frameRef.current % SORT_INTERVAL === 0) {
            sortStars();
        }

        // ── Target detection ───────────────────────────────────────
        const cx = size.width / 2;
        const cy = size.height / 2;
        const cosH = Math.cos(-heading + Math.PI / 2);
        const sinH = Math.sin(-heading + Math.PI / 2);
        let bestIdx = -1;
        let bestDist = TARGET_DIST_MAX;

        for (let i = 0; i < stars.length; i++) {
            const star = stars[i];
            if (star.z < TARGET_Z_MIN) continue;
            const relX = star.worldX - pos.x;
            const relY = star.worldY - pos.y;
            const rotX = relX * cosH - relY * sinH;
            const rotY = relX * sinH + relY * cosH;
            const projX = cx + rotX / star.z;
            const projY = cy + rotY / star.z;
            const dx = projX - cx;
            const dy = projY - cy;
            const dist = Math.sqrt(dx * dx + dy * dy);
            if (dist < bestDist) {
                bestDist = dist;
                bestIdx = i;
            }
        }
        targetIndexRef.current = bestIdx;

        // ── Redraw ─────────────────────────────────────────────────
        if (layerRef.current) {
            layerRef.current.batchDraw();
        }

        rafRef.current = requestAnimationFrame(tick);
    }, [sortStars]);

    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
        stageSizeRef.current = stageSize;
        rocketPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
        headingRef.current = -Math.PI / 2;
        velocityRef.current = 0;
        frameRef.current = 0;
        targetIndexRef.current = -1;

        // Build star array from posts
        const stars = [];
        for (let i = 0; i < galaxyPosts.length; i++) {
            const post = galaxyPosts[i];
            const uid = post.users?.id ?? post.user_id;
            const likeCount = post.like_count != null
                ? post.like_count
                : (Array.isArray(post.likes) && post.likes[0]?.count != null
                    ? post.likes[0].count : 0);
            const color = getStarColor(uid);
            const rng = seededRandom(simpleHash(post.id || String(i)));
            stars.push({
                postId: post.id,
                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
                z: MIN_Z + rng() * (MAX_Z - MIN_Z),
                color,
                colorRgb: parseHex(color),
                radius: getStarRadius(likeCount),
                title: post.title || 'Untitled',
                authorName: post.users?.name || post.user_name || 'Anonymous',
                post,
            });
        }

        starsRef.current = stars;

        // Build sorted indices (far → near)
        const indices = new Array(stars.length);
        for (let i = 0; i < stars.length; i++) indices[i] = i;
        indices.sort((a, b) => stars[b].z - stars[a].z);
        sortedIndicesRef.current = indices;

        // Key listeners
        const onKeyDown = (e) => {
            const key = e.key.toLowerCase();
            if (key === 'w' || key === 'arrowup') keysRef.current.w = true;
            if (key === 's' || key === 'arrowdown') keysRef.current.s = true;
            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
        };
        const onKeyUp = (e) => {
            const key = e.key.toLowerCase();
            if (key === 'w' || key === 'arrowup') keysRef.current.w = false;
            if (key === 's' || key === 'arrowdown') keysRef.current.s = false;
            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
        };

        window.addEventListener('keydown', onKeyDown);
        window.addEventListener('keyup', onKeyUp);

        // Store cleanup refs
        keysRef.current = { w: false, s: false, a: false, d: false };
        isActiveRef.current = true;

        // Store listener refs for cleanup
        rocketPosRef.current._onKeyDown = onKeyDown;
        rocketPosRef.current._onKeyUp = onKeyUp;

        // Start rAF
        rafRef.current = requestAnimationFrame(tick);
    }, [tick]);

    const exit = useCallback(() => {
        isActiveRef.current = false;
        if (rafRef.current) {
            cancelAnimationFrame(rafRef.current);
            rafRef.current = null;
        }
        // Remove key listeners
        const pos = rocketPosRef.current;
        if (pos._onKeyDown) {
            window.removeEventListener('keydown', pos._onKeyDown);
            window.removeEventListener('keyup', pos._onKeyUp);
            delete pos._onKeyDown;
            delete pos._onKeyUp;
        }
        keysRef.current = { w: false, s: false, a: false, d: false };
    }, []);

    const project = useCallback((star, cx, cy) => {
        const pos = rocketPosRef.current;
        const heading = headingRef.current;
        const relX = star.worldX - pos.x;
        const relY = star.worldY - pos.y;
        const cosH = Math.cos(-heading + Math.PI / 2);
        const sinH = Math.sin(-heading + Math.PI / 2);
        const rotX = relX * cosH - relY * sinH;
        const rotY = relX * sinH + relY * cosH;
        return {
            projX: cx + rotX / star.z,
            projY: cy + rotY / star.z,
            scale: 1 / star.z,
        };
    }, []);

    const getTargetedPost = useCallback(() => {
        const idx = targetIndexRef.current;
        if (idx < 0 || idx >= starsRef.current.length) return null;
        return starsRef.current[idx].post;
    }, []);

    const getSpeedRatio = useCallback(() => {
        return velocityRef.current / MAX_SPEED;
    }, []);

    return {
        enter,
        exit,
        layerRef,
        starsRef,
        sortedIndicesRef,
        rocketPos: rocketPosRef,
        heading: headingRef,
        velocity: velocityRef,
        targetIndexRef,
        stageSizeRef,
        project,
        isActive: isActiveRef,
        getTargetedPost,
        getSpeedRatio,
    };
};

export default useRocketMode;

