    transition: background 0.2s, border-color 0.2s;
}

.labelInputCreate:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

.labelInputCreate:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.labelInputCancel {
    padding: 7px 14px;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 10px;
    color: rgba(255, 255, 255, 0.5);
    font-size: 13px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
}

.labelInputCancel:hover {
    background: rgba(255, 255, 255, 0.12);
    color: rgba(255, 255, 255, 0.8);
}

/* Constellation travel button */
.constellationBtn {
    display: inline-block;
    padding: 8px 22px;
    background: rgba(176, 95, 255, 0.12);
    border: 1px solid rgba(176, 95, 255, 0.35);
    border-radius: 10px;
    color: #b05fff;
    font-size: 12px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 100%;
}

.constellationBtn:hover {
    background: rgba(176, 95, 255, 0.22);
    border-color: rgba(176, 95, 255, 0.55);
}

/* Wormhole warp overlay */
.warpOverlay {
    position: absolute;
    inset: 0;
    z-index: 10;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        transparent 20%,
        rgba(95, 146, 255, 0.15) 60%,
        rgba(0, 0, 0, 0.6) 100%
    );
    animation: warpPulse 1.8s ease-in-out forwards;
}

@keyframes warpPulse {
    0%   { opacity: 0; }
    15%  { opacity: 1; }
    85%  { opacity: 1; }
    100% { opacity: 0; }
}

@media (max-width: 600px) {
    .previewPanel {
        width: auto;
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 260px;
        box-sizing: border-box;
    }

    .backButton {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .distanceTracker {
        bottom: auto;
        top: 52px;
        right: 12px;
        left: auto;
    }

    .minimap {
        width: 100px;
        height: 100px;
        bottom: 12px;
        left: 12px;
    }

    .galaxyPreviewPanel {
        width: calc(100% - 32px);
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 300px;
    }

    .linkModeButton {
        top: 12px;
        left: auto;
        right: 12px;
        padding: 8px 14px;
        font-size: 12px;
    }

    .linkModeIndicator {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        white-space: normal;
        font-size: 12px;
    }

    .labelInputPanel {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        min-width: 0;
        max-width: none;
    }

    .labelInputHeader {
        white-space: normal;
        font-size: 12px;
    }
}

