  7→const BRAKE = 0.15;
  8→const FRICTION = 0.985;
  9→const TURN_RATE = 0.035;
 10→const MIN_Z = 0.5;
 11→const MAX_Z = 800;
 12→const SPAWN_Z_RANGE = 400;
 13→const SORT_INTERVAL = 5;
 14→const TARGET_DIST_MAX = 150;
 15→const TARGET_Z_MIN = 2;
 16→const TWO_PI = Math.PI * 2;
 17→
 18→/** Parse "#5f92ff" → { r, g, b } */
 19→const parseHex = (hex) => ({
 20→    r: parseInt(hex.slice(1, 3), 16),
 21→    g: parseInt(hex.slice(3, 5), 16),
 22→    b: parseInt(hex.slice(5, 7), 16),
 23→});
 24→
 25→/** Seeded pseudo-random from integer seed */
 26→const seededRandom = (seed) => {
 27→    let s = seed | 0;
 28→    return () => {
 29→        s = (s * 1664525 + 1013904223) | 0;
 30→        return ((s >>> 0) / 4294967296);
 31→    };
 32→};
 33→
 34→const useRocketMode = () => {
 35→    const isActiveRef = useRef(false);
 36→    const rocketPosRef = useRef({ x: 0, y: 0 });
 37→    const headingRef = useRef(-Math.PI / 2);
 38→    const velocityRef = useRef(0);
 39→    const starsRef = useRef([]);
 40→    const sortedIndicesRef = useRef([]);
 41→    const keysRef = useRef({ w: false, s: false, a: false, d: false });
 42→    const targetIndexRef = useRef(-1);
 43→    const frameRef = useRef(0);
 44→    const layerRef = useRef(null);
 45→    const rafRef = useRef(null);
 46→    const stageSizeRef = useRef({ width: 0, height: 0 });
 47→
 48→    const sortStars = useCallback(() => {
 49→        const stars = starsRef.current;
 50→        const indices = sortedIndicesRef.current;
 51→        // Simple insertion sort — fast for nearly-sorted arrays
 52→        for (let i = 1; i < indices.length; i++) {
 53→            const key = indices[i];
 54→            let j = i - 1;
 55→            while (j >= 0 && stars[indices[j]].z < stars[key].z) {
 56→                indices[j + 1] = indices[j];
 57→                j--;
 58→            }
 59→            indices[j + 1] = key;
 60→        }
 61→    }, []);
 62→
 63→    const tick = useCallback(() => {
 64→        if (!isActiveRef.current) return;
 65→
 66→        const keys = keysRef.current;
 67→        const pos = rocketPosRef.current;
 68→        const stars = starsRef.current;
 69→        const size = stageSizeRef.current;
 70→
 71→        // ── Heading ────────────────────────────────────────────────
 72→        if (keys.a) headingRef.current -= TURN_RATE;
 73→        if (keys.d) headingRef.current += TURN_RATE;
 74→
 75→        // ── Velocity ───────────────────────────────────────────────
 76→        if (keys.w) {
 77→            velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
 78→        } else if (keys.s) {
 79→            velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
 80→        } else {
 81→            velocityRef.current *= FRICTION;
 82→            if (velocityRef.current < 0.01) velocityRef.current = 0;
 83→        }
 84→
 85→        const heading = headingRef.current;
 86→        const velocity = velocityRef.current;
 87→
 88→        // ── Position ───────────────────────────────────────────────
 89→        pos.x += Math.cos(heading) * velocity;
 90→        pos.y += Math.sin(heading) * velocity;
 91→
 92→        // ── Z update + recycle ─────────────────────────────────────
 93→        const zStep = velocity * 0.5;
 94→        for (let i = 0; i < stars.length; i++) {
 95→            const star = stars[i];
 96→            star.z -= zStep;
 97→            if (star.z < MIN_Z) {
 98→                star.z = MAX_Z - Math.random() * SPAWN_Z_RANGE;
 99→                star.worldX = pos.x + (Math.random() - 0.5) * 4000;
100→                star.worldY = pos.y + (Math.random() - 0.5) * 4000;
101→            }
102→        }
103→
104→        // ── Sort (every N frames) ─────────────────────────────────
105→        frameRef.current++;
106→        if (frameRef.current % SORT_INTERVAL === 0) {
107→            sortStars();
108→        }
109→
110→        // ── Target detection ───────────────────────────────────────
111→        const cx = size.width / 2;
112→        const cy = size.height / 2;
113→        const cosH = Math.cos(-heading + Math.PI / 2);
114→        const sinH = Math.sin(-heading + Math.PI / 2);
115→        let bestIdx = -1;
116→        let bestDist = TARGET_DIST_MAX;
117→
118→        for (let i = 0; i < stars.length; i++) {
119→            const star = stars[i];
120→            if (star.z < TARGET_Z_MIN) continue;
121→            const relX = star.worldX - pos.x;
122→            const relY = star.worldY - pos.y;
123→            const rotX = relX * cosH - relY * sinH;
124→            const rotY = relX * sinH + relY * cosH;
125→            const projX = cx + rotX / star.z;
126→            const projY = cy + rotY / star.z;
127→            const dx = projX - cx;
128→            const dy = projY - cy;
129→            const dist = Math.sqrt(dx * dx + dy * dy);
130→            if (dist < bestDist) {
131→                bestDist = dist;
132→                bestIdx = i;
133→            }
134→        }
135→        targetIndexRef.current = bestIdx;
136→
137→        // ── Redraw ─────────────────────────────────────────────────
138→        if (layerRef.current) {
139→            layerRef.current.batchDraw();
140→        }
141→
142→        rafRef.current = requestAnimationFrame(tick);
143→    }, [sortStars]);
144→
145→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
146→        stageSizeRef.current = stageSize;
147→        rocketPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
148→        headingRef.current = -Math.PI / 2;
149→        velocityRef.current = 0;
150→        frameRef.current = 0;
151→        targetIndexRef.current = -1;
152→
153→        // Build star array from posts
154→        const stars = [];
155→        for (let i = 0; i < galaxyPosts.length; i++) {
156→            const post = galaxyPosts[i];
157→            const uid = post.users?.id ?? post.user_id;
158→            const likeCount = post.like_count != null
159→                ? post.like_count
160→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
161→                    ? post.likes[0].count : 0);
162→            const color = getStarColor(uid);
163→            const rng = seededRandom(simpleHash(post.id || String(i)));
164→            stars.push({
165→                postId: post.id,
166→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
167→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
168→                z: MIN_Z + rng() * (MAX_Z - MIN_Z),
169→                color,
170→                colorRgb: parseHex(color),
171→                radius: getStarRadius(likeCount),
172→                title: post.title || 'Untitled',
173→                authorName: post.users?.name || post.user_name || 'Anonymous',
174→                post,
175→            });
176→        }
177→
178→        starsRef.current = stars;
179→
180→        // Build sorted indices (far → near)
181→        const indices = new Array(stars.length);
182→        for (let i = 0; i < stars.length; i++) indices[i] = i;
183→        indices.sort((a, b) => stars[b].z - stars[a].z);
184→        sortedIndicesRef.current = indices;
185→
186→        // Key listeners
187→        const onKeyDown = (e) => {
188→            const key = e.key.toLowerCase();
189→            if (key === 'w' || key === 'arrowup') keysRef.current.w = true;
190→            if (key === 's' || key === 'arrowdown') keysRef.current.s = true;
191→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
192→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
193→        };
194→        const onKeyUp = (e) => {
195→            const key = e.key.toLowerCase();
196→            if (key === 'w' || key === 'arrowup') keysRef.current.w = false;
197→            if (key === 's' || key === 'arrowdown') keysRef.current.s = false;
198→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
199→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
200→        };
201→
202→        window.addEventListener('keydown', onKeyDown);
203→        window.addEventListener('keyup', onKeyUp);
204→
205→        // Store cleanup refs
206→        keysRef.current = { w: false, s: false, a: false, d: false };
207→        isActiveRef.current = true;
208→
209→        // Store listener refs for cleanup
210→        rocketPosRef.current._onKeyDown = onKeyDown;
211→        rocketPosRef.current._onKeyUp = onKeyUp;
212→
213→        // Start rAF
214→        rafRef.current = requestAnimationFrame(tick);
215→    }, [tick]);
216→
217→    const exit = useCallback(() => {
218→        isActiveRef.current = false;
219→        if (rafRef.current) {
220→            cancelAnimationFrame(rafRef.current);
221→            rafRef.current = null;
222→        }
223→        // Remove key listeners
224→        const pos = rocketPosRef.current;
225→        if (pos._onKeyDown) {
226→            window.removeEventListener('keydown', pos._onKeyDown);
227→            window.removeEventListener('keyup', pos._onKeyUp);
228→            delete pos._onKeyDown;
229→            delete pos._onKeyUp;
230→        }
231→        keysRef.current = { w: false, s: false, a: false, d: false };
232→    }, []);
233→
234→    const project = useCallback((star, cx, cy) => {
235→        const pos = rocketPosRef.current;
236→        const heading = headingRef.current;
237→        const relX = star.worldX - pos.x;
238→        const relY = star.worldY - pos.y;
239→        const cosH = Math.cos(-heading + Math.PI / 2);
240→        const sinH = Math.sin(-heading + Math.PI / 2);
241→        const rotX = relX * cosH - relY * sinH;
242→        const rotY = relX * sinH + relY * cosH;
243→        return {
244→            projX: cx + rotX / star.z,
245→            projY: cy + rotY / star.z,
246→            scale: 1 / star.z,
247→        };
248→    }, []);
249→
250→    const getTargetedPost = useCallback(() => {
251→        const idx = targetIndexRef.current;
252→        if (idx < 0 || idx >= starsRef.current.length) return null;
253→        return starsRef.current[idx].post;
254→    }, []);
255→
256→    const getSpeedRatio = useCallback(() => {
257→        return velocityRef.current / MAX_SPEED;
258→    }, []);
259→
260→    return {
261→        enter,
262→        exit,
263→        layerRef,
264→        starsRef,
265→        sortedIndicesRef,
266→        rocketPos: rocketPosRef,
267→        heading: headingRef,
268→        velocity: velocityRef,
269→        targetIndexRef,
270→        stageSizeRef,
271→        project,
272→        isActive: isActiveRef,
273→        getTargetedPost,
274→        getSpeedRatio,
275→    };
276→};
277→
278→export default useRocketMode;
279→

  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→
  4→const TWO_PI = Math.PI * 2;
  5→const SPEED_LINE_COUNT = 30;
  6→
  7→const RocketLayer = React.memo(({ rocketMode }) => {
  8→    const {
  9→        layerRef, starsRef, sortedIndicesRef, velocity, targetIndexRef,
 10→        stageSizeRef, project, getSpeedRatio,
 11→    } = rocketMode;
 12→
 13→    const shapeRef = useRef(null);
 14→    const timeRef = useRef(0);
 15→
 16→    // Attach the Konva Layer ref so the hook can call batchDraw
 17→    const layerCallbackRef = useCallback((node) => {
 18→        layerRef.current = node;
 19→    }, [layerRef]);
 20→
 21→    // Keep time ticking for pulsing effects
 22→    useEffect(() => {
 23→        const update = () => {
 24→            timeRef.current = performance.now();
 25→        };
 26→        const id = setInterval(update, 16);
 27→        return () => clearInterval(id);
 28→    }, []);
 29→
 30→    return (
 31→        <Layer ref={layerCallbackRef} listening={false}>
 32→            <Shape
 33→                ref={shapeRef}
 34→                sceneFunc={(ctx) => {
 35→                    const size = stageSizeRef.current;
 36→                    const cx = size.width / 2;
 37→                    const cy = size.height / 2;
 38→                    const stars = starsRef.current;
 39→                    const sorted = sortedIndicesRef.current;
 40→                    const speedRatio = getSpeedRatio();
 41→                    const time = timeRef.current || performance.now();
 42→                    const targetIdx = targetIndexRef.current;
 43→                    const bufferX = size.width / 2 + 200;
 44→                    const bufferY = size.height / 2 + 200;
 45→
 46→                    // ── 1. Speed lines (behind stars) ──────────────────
 47→                    if (speedRatio > 0.4) {
 48→                        const lineAlpha = (speedRatio - 0.4) / 0.6;
 49→                        ctx.strokeStyle = `rgba(180,210,255,${lineAlpha * 0.3})`;
 50→                        ctx.lineWidth = 1;
 51→
 52→                        for (let i = 0; i < SPEED_LINE_COUNT; i++) {
 53→                            const angle = (i / SPEED_LINE_COUNT) * TWO_PI;
 54→                            const innerR = 80 + Math.sin(time * 0.002 + i) * 20;
 55→                            const outerR = innerR + 60 + speedRatio * 200;
 56→                            ctx.beginPath();
 57→                            ctx.moveTo(
 58→                                cx + Math.cos(angle) * innerR,
 59→                                cy + Math.sin(angle) * innerR
 60→                            );
 61→                            ctx.lineTo(
 62→                                cx + Math.cos(angle) * outerR,
 63→                                cy + Math.sin(angle) * outerR
 64→                            );
 65→                            ctx.stroke();
 66→                        }
 67→                    }
 68→
 69→                    // ── 2. Stars (painter's algorithm, far first) ──────
 70→                    for (let si = 0; si < sorted.length; si++) {
 71→                        const idx = sorted[si];
 72→                        const star = stars[idx];
 73→                        const { projX, projY, scale } = project(star, cx, cy);
 74→
 75→                        // Viewport cull
 76→                        if (projX < cx - bufferX || projX > cx + bufferX ||
 77→                            projY < cy - bufferY || projY > cy + bufferY) continue;
 78→
 79→                        const baseRadius = star.radius * scale * 40;
 80→                        if (baseRadius < 0.3) continue;
 81→
 82→                        const stretchX = 1 + speedRatio * 2.5;
 83→                        const opacity = Math.max(0.1, 1 - speedRatio * 0.6);
 84→                        const drawR = Math.min(baseRadius, 60);
 85→                        const { r, g, b } = star.colorRgb;
 86→
 87→                        ctx.save();
 88→                        ctx.translate(projX, projY);
 89→                        ctx.scale(stretchX, 1);
 90→
 91→                        // Outer glow
 92→                        const glowR = drawR * 2.5;
 93→                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, glowR);
 94→                        grad.addColorStop(0, `rgba(${r},${g},${b},${opacity * 0.5})`);
 95→                        grad.addColorStop(0.4, `rgba(${r},${g},${b},${opacity * 0.15})`);
 96→                        grad.addColorStop(1, 'rgba(0,0,0,0)');
 97→                        ctx.beginPath();
 98→                        ctx.arc(0, 0, glowR, 0, TWO_PI);
 99→                        ctx.fillStyle = grad;
100→                        ctx.fill();
101→
102→                        // Core (white-hot center)
103→                        const coreR = drawR * 0.4;
104→                        ctx.beginPath();
105→                        ctx.arc(0, 0, Math.max(coreR, 0.5), 0, TWO_PI);
106→                        ctx.fillStyle = `rgba(255,255,255,${opacity * 0.9})`;
107→                        ctx.fill();
108→
109→                        ctx.restore();
110→
111→                        // ── 3. Targeting bracket ───────────────────────
112→                        if (idx === targetIdx) {
113→                            const pulse = 0.6 + 0.4 * Math.sin(time * 0.004);
114→                            const bracketSize = Math.max(drawR * stretchX * 4, 18);
115→                            const half = bracketSize / 2;
116→                            const arm = bracketSize * 0.35;
117→
118→                            ctx.strokeStyle = `rgba(0,255,255,${pulse})`;
119→                            ctx.lineWidth = 1.5;
120→                            ctx.setLineDash([3, 3]);
121→
122→                            // Top-left
123→                            ctx.beginPath();
124→                            ctx.moveTo(projX - half, projY - half + arm);
125→                            ctx.lineTo(projX - half, projY - half);
126→                            ctx.lineTo(projX - half + arm, projY - half);
127→                            ctx.stroke();
128→
129→                            // Top-right
130→                            ctx.beginPath();
131→                            ctx.moveTo(projX + half - arm, projY - half);
132→                            ctx.lineTo(projX + half, projY - half);
133→                            ctx.lineTo(projX + half, projY - half + arm);
134→                            ctx.stroke();
135→
136→                            // Bottom-right
137→                            ctx.beginPath();
138→                            ctx.moveTo(projX + half, projY + half - arm);
139→                            ctx.lineTo(projX + half, projY + half);
140→                            ctx.lineTo(projX + half - arm, projY + half);
141→                            ctx.stroke();
142→
143→                            // Bottom-left
144→                            ctx.beginPath();
145→                            ctx.moveTo(projX - half + arm, projY + half);
146→                            ctx.lineTo(projX - half, projY + half);
147→                            ctx.lineTo(projX - half, projY + half - arm);
148→                            ctx.stroke();
149→
150→                            ctx.setLineDash([]);
151→                        }
152→                    }
153→                }}
154→                perfectDrawEnabled={false}
155→                listening={false}
156→            />
157→        </Layer>
158→    );
159→});
160→
161→RocketLayer.displayName = 'RocketLayer';
162→
163→export default RocketLayer;
164→

 1→import { useState, useEffect, useRef, useCallback } from 'react';
 2→import styles from '../Universe.module.css';
 3→
 4→const RocketHUD = ({ rocketMode, onExit, onInteract }) => {
 5→    const [speed, setSpeed] = useState(0);
 6→    const [targetInfo, setTargetInfo] = useState(null);
 7→    const pollRef = useRef(null);
 8→
 9→    // Poll refs at 10 Hz for HUD display
10→    useEffect(() => {
11→        pollRef.current = setInterval(() => {
12→            setSpeed(rocketMode.getSpeedRatio());
13→
14→            const idx = rocketMode.targetIndexRef.current;
15→            const stars = rocketMode.starsRef.current;
16→            if (idx >= 0 && idx < stars.length) {
17→                const star = stars[idx];
18→                setTargetInfo({ title: star.title, author: star.authorName });
19→            } else {
20→                setTargetInfo(null);
21→            }
22→        }, 100);
23→
24→        return () => {
25→            if (pollRef.current) clearInterval(pollRef.current);
26→        };
27→    }, [rocketMode]);
28→
29→    // Key bindings for Enter/Space (interact) and Escape (exit)
30→    const handleKey = useCallback((e) => {
31→        if (e.key === 'Enter' || e.key === ' ') {
32→            e.preventDefault();
33→            onInteract();
34→        } else if (e.key === 'Escape') {
35→            e.preventDefault();
36→            onExit();
37→        }
38→    }, [onInteract, onExit]);
39→
40→    useEffect(() => {
41→        window.addEventListener('keydown', handleKey);
42→        return () => window.removeEventListener('keydown', handleKey);
43→    }, [handleKey]);
44→
45→    return (
46→        <div className={styles.rocketHud}>
47→            {/* Exit button */}
48→            <button className={styles.rocketExitBtn} onClick={onExit}>
49→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
50→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
51→                </svg>
52→                Exit Rocket
53→            </button>
54→
55→            {/* Target info (below center) */}
56→            {targetInfo && (
57→                <div className={styles.rocketTarget}>
58→                    <div className={styles.rocketTargetTitle}>{targetInfo.title}</div>
59→                    <div className={styles.rocketTargetAuthor}>by {targetInfo.author}</div>
60→                    <div className={styles.rocketTargetPrompt}>Press ENTER to read</div>
61→                </div>
62→            )}
63→
64→            {/* Speed bar */}
65→            <div className={styles.rocketSpeedBar}>
66→                <span className={styles.rocketSpeedLabel}>SPD</span>
67→                <div className={styles.rocketSpeedTrack}>
68→                    <div
69→                        className={styles.rocketSpeedFill}
70→                        style={{ width: `${Math.round(speed * 100)}%` }}
71→                    />
72→                </div>
73→                <span className={styles.rocketSpeedValue}>{Math.round(speed * 100)}%</span>
74→            </div>
75→
76→            {/* Controls hint */}
77→            <div className={styles.rocketControls}>
78→                <span>W/S Throttle</span>
79→                <span>A/D Turn</span>
80→                <span>ENTER Read</span>
81→                <span>ESC Exit</span>
82→            </div>
83→        </div>
84→    );
85→};
