// After:
const camPosRef = useRef({ x: 0, y: 0, z: 0 });   // 3D world position
const yawRef    = useRef(0);                         // rotation around Y axis (horizontal)
const pitchRef  = useRef(0);                         // rotation around X axis (vertical)
